use std::io::stdin;
fn main() {
    let mut text = String::new();
    stdin().read_line(&mut text).unwrap();
    let text: Vec<usize> = text
        .trim()
        .split_whitespace()
        .collect::<Vec<&str>>()
        .iter()
        .map(|e| e.parse().unwrap())
        .collect();
    let (a, b) = (text[0], text[1]);
    let mut values = vec![];
    if a == truc(b, a, &mut values) {
        println!("YES");
        println!("{}", values.len());
        let mut text = String::new();
        text.push_str(a.to_string().as_str());
        for i in (0..(values.len() - 1)).rev() {
            text = format!("{} {}", text, values[i]);
        }
        println!("{}", text)
    } else {
        println!("NO")
    }
}

fn truc(i: usize, b: usize, v: &mut Vec<usize>) -> usize {
    v.push(i);
    if i == b {
        i
    } else if i % 10 == 1 && i > 1 {
        truc((i - 1) / 10, b, v)
    } else if i % 2 == 0 {
        truc(i / 2, b, v)
    } else {
        i
    }
}
